import{_ as o}from"./chunks/quick_control_icon.Cc9UwUrp.js";import{_ as a,c as i,o as l,aj as t}from"./chunks/framework.CjkNaYQl.js";const p=JSON.parse('{"title":"4. 自主練習","description":"","frontmatter":{},"headers":[],"relativePath":"intermediate/4.md","filePath":"intermediate/4.md"}'),d={name:"intermediate/4.md"};function c(r,e,n,s,h,m){return l(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="_4-自主練習" tabindex="-1">4. 自主練習 <a class="header-anchor" href="#_4-自主練習" aria-label="Permalink to &quot;4. 自主練習&quot;">​</a></h1><h2 id="題目一-迴圈" tabindex="-1">題目一：迴圈 <a class="header-anchor" href="#題目一-迴圈" aria-label="Permalink to &quot;題目一：迴圈&quot;">​</a></h2><p>用與<a href="/YMSH_TMRobot_Textbook/basic/6.html">初階篇的自主練習</a>相同題目，但重覆執行六次。</p><h2 id="驗證一" tabindex="-1">驗證一 <a class="header-anchor" href="#驗證一" aria-label="Permalink to &quot;驗證一&quot;">​</a></h2><ol><li>麻將放置板放置位置不固定，看手臂是否有辦法精準將麻將放到板中凹槽並重複六次（建議板子放置不要超過 180＆deg;）</li><li>在重複執行六次後，是否自動退出專案執行畫面</li></ol><div class="info custom-block"><p class="custom-block-title">小提示</p><p>在執行迴圈時，記得將麻將塊拿起來，否則會撞機</p></div><h2 id="答案一" tabindex="-1">答案一 <a class="header-anchor" href="#答案一" aria-label="Permalink to &quot;答案一&quot;">​</a></h2><p>在<a href="/YMSH_TMRobot_Textbook/basic/6.html">初階篇的自主練習</a>的基礎上，接續下去。</p><ol><li>在上方欄位，找到&#39;管理員&#39;選擇新增變數</li><li>利用&#39;Set&#39;使每執行結束後，變數&#39;＋1&#39;</li><li>使用&#39;If&#39;建立迴圈</li><li></li></ol><h2 id="題目二-放滿板子" tabindex="-1">題目二：放滿板子 <a class="header-anchor" href="#題目二-放滿板子" aria-label="Permalink to &quot;題目二：放滿板子&quot;">​</a></h2><p>將六塊麻將塊依序放置於六個凹槽的板子上（放麻將塊的板子）。</p><h2 id="驗證二" tabindex="-1">驗證二 <a class="header-anchor" href="#驗證二" aria-label="Permalink to &quot;驗證二&quot;">​</a></h2><ol><li>麻將塊是否先排滿一列後，換行再繼續</li><li>麻將是否放置於凹槽內</li></ol><h2 id="答案二" tabindex="-1">答案二 <a class="header-anchor" href="#答案二" aria-label="Permalink to &quot;答案二&quot;">​</a></h2><p>在<a href="/YMSH_TMRobot_Textbook/basic/6.html">初階篇的自主練習</a>的基礎上，接續下去。 1. 2. 3. 4.</p><h2 id="題目三-疊高高" tabindex="-1">題目三：疊高高 <a class="header-anchor" href="#題目三-疊高高" aria-label="Permalink to &quot;題目三：疊高高&quot;">​</a></h2><p>將麻塊以堆疊的方式，疊三至五塊麻將塊。</p><h2 id="驗證三" tabindex="-1">驗證三 <a class="header-anchor" href="#驗證三" aria-label="Permalink to &quot;驗證三&quot;">​</a></h2><ol><li>測試<code>vision</code>是否能正確辨識到麻將塊</li><li>麻將塊放置位置不固定，看手臂是否有辦法精準夾到麻將（建議麻將放置不要旋轉超過 180°）</li><li>流程結束後，是否自動退出專案執行畫面</li></ol><h2 id="答案三" tabindex="-1">答案三 <a class="header-anchor" href="#答案三" aria-label="Permalink to &quot;答案三&quot;">​</a></h2><ol><li>``</li><li><code>Point</code>（Robot Base）：可以在初始位置先打一個 <code>Point</code>，要足夠高，以免移動到視覺任務的點位時撞機</li><li><code>Vision</code>（Positioning，Robot Base）：移動到放置麻將的區塊後，設定 <code>物件定位</code> 的視覺任務，辨識麻將上的 <strong>TM</strong> Logo（此步完成後，會自動建立 Vision Base）</li><li><code>Point</code>（Vision Base）：將手臂向下拉到麻將上，且手臂可以夾起麻將的位置（麻將位置不能移動到），可利用畫面上方 <img src="'+o+'" alt="Quick Control 圖標" style="width:25px;display:inline;vertical-align:middle;margin:0 5px;">，並用控制器 <code>+</code> 和 <code>-</code> 來細微控制坐標</li><li><code>Set</code>：末端模組的 <code>DO_0</code> 設為 <code>H</code>，並按下 <code>輸出測試</code> 以夾起麻將</li><li><code>Wait for</code>：等待 <code>500 ms</code>，確保麻將能被夾起</li><li><code>Move</code>：<code>Z</code> 設為 <code>-100 mm</code>，確保手臂不會撞機，此步也可用另一個垂直向上的 <code>Point</code> 代替</li><li><code>point</code>（Robot Base）：任意選擇一個點作為起始點</li><li><code>Set</code>：末端模組的 <code>DO_0</code> 設為 <code>L</code> ，並按下 <code>輸出測試</code> 以放下麻將</li><li></li></ol>',21)])])}const u=a(d,[["render",c]]);export{p as __pageData,u as default};
